CREATE VIEW `dim_user_hk_account_info_view` (`user_id` COMMENT "用户id", `account` COMMENT "用户账户", `pass_word` COMMENT "密码", `salt` COMMENT "加密", `sex` COMMENT "性别", `nick` COMMENT "昵称", `wrong_num` COMMENT "设置密码错误次数", `wrong_time` COMMENT "设置密码错误时间", `is_lock` COMMENT "是否锁住", `lock_time` COMMENT "锁住时间", `reg_time` COMMENT "注册时间", `last_login_time` COMMENT "最近一次登录时间", `email` COMMENT "邮箱", `phone` COMMENT "手机号", `imei` COMMENT "设备imei", `sms_code` COMMENT "短信验证码", `has_user_setpwd` COMMENT "是否设置过密码", `reg_ip` COMMENT "注册时ip", `login_ip` COMMENT "登录ip", `sr_createtime` COMMENT "starrocks数据注入时间", `sr_updatetime` COMMENT "starrocks数据更新时间")
